.list5 {
	display: grid;
	grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
	gap: 20px;

	.list-item {
		border-radius: $radius;
		overflow: hidden;
		cursor: pointer;

		.card-inner {
			background: $white;
			border-radius: $radius;
			box-shadow: $shadow;
			overflow: hidden;
			transition: all 0.35s cubic-bezier(0.4, 0, 0.2, 1);
			border: 1px solid $border;

			&:hover {
				transform: translateY(-4px);
				box-shadow: 0 12px 28px rgba(14,165,233,0.12);
				border-color: $primary;

				.card-action {
					background: linear-gradient(135deg, rgba(14,165,233,0.08), rgba(124,58,237,0.05));
					.el-icon { transform: translateX(3px); }
				}
			}
		}

		.imgbox {
			height: 200px;
			overflow: hidden;
			position: relative;
			img {
				width: 100%;
				height: 100%;
				object-fit: cover;
				display: block;
				transition: transform 0.5s cubic-bezier(0.4, 0, 0.2, 1);
			}
			&::after {
				content: '';
				position: absolute;
				bottom: 0;
				left: 0;
				right: 0;
				height: 60px;
				background: linear-gradient(transparent, rgba(0,0,0,0.3));
				pointer-events: none;
			}
		}
		.card-inner:hover .imgbox img {
			transform: scale(1.08);
		}

		.card-badge {
			position: absolute;
			top: 12px;
			left: 12px;
			background: linear-gradient(135deg, $primary, $purple);
			color: #fff;
			font-size: 11px;
			font-weight: 600;
			padding: 4px 12px;
			border-radius: 20px;
			z-index: 2;
			letter-spacing: 1px;
			box-shadow: 0 2px 8px rgba(14,165,233,0.3);
			.el-icon { margin-right: 3px; vertical-align: middle; }
		}

		.infoBox {
			padding: 16px;

			.card-title {
				font-size: 15px;
				color: $text-dark;
				font-weight: 600;
				margin-bottom: 8px;
				overflow: hidden;
				text-overflow: ellipsis;
				white-space: nowrap;
			}

			.card-tag {
				display: inline-block;
				font-size: 11px;
				color: $primary;
				background: rgba(14,165,233,0.08);
				padding: 2px 10px;
				border-radius: 10px;
				margin-bottom: 12px;
			}

			.bottomInfo {
				display: flex;
				justify-content: space-between;
				align-items: center;
				gap: 8px;
				padding: 10px 0;
				border-top: 1px dashed $border;

				.time_item,
				.publisher_item {
					display: flex;
					align-items: center;
					gap: 4px;
					min-width: 0;
				}
				.text {
					font-size: 12px;
					color: $text-gray;
				}
				.el-icon {
					font-size: 13px;
					color: $primary;
				}
			}

			.card-action {
				display: flex;
				align-items: center;
				justify-content: space-between;
				padding: 10px 14px;
				margin: 8px -16px -16px;
				background: $bg;
				border-top: 1px solid $border;
				transition: all 0.3s;

				.action-text {
					font-size: 13px;
					color: $primary;
					font-weight: 500;
				}
				.el-icon {
					font-size: 14px;
					color: $primary;
					transition: transform 0.3s;
				}
			}
		}
	}
}

