							seriesObj = Object.assign(seriesObj , this.pie2.series)
							const gridObj = this.pie2.grid
							option = {
								backgroundColor: this.pie2.backgroundColor,
								color: this.pie2.color,
								title: titleObj,
								legend: legendObj,
								grid: gridObj,
								tooltip: tooltipObj,
								series: [seriesObj]
							};
							// 使用刚指定的配置项和数据显示图表。
							ziliaoleixingChart1.setOption(option);
							  //根据窗口的大小变动图表
							window.onresize = function() {
								ziliaoleixingChart1.resize();
							};
						}
					})
				})
			},

			discussClick (row){
				let params = {
					refid: row.id
				}
				if(this.centerType){
					params.centerType = 1
				}
				this.$router.push({path: '/main/discussxuexiziliao', query: params});
			},
			chapterClick (row){
				let params = {
					refid: row.id
				}
				if(this.centerType){
